import React from "react";

function Alerts({ stock }) {
  return (
    <div>
      <h3>⏰ Expiry Alerts</h3>
      {stock.map((item, index) =>
        item.name === "Milk" ? (
          <p key={index} style={{ color: "red" }}>
            ⚠️ Milk will expire soon!
          </p>
        ) : null
      )}
    </div>
  );
}

export default Alerts;
